// Palindrome Finder - Concrete Implementation
// Finds longest palindrome in text using expanding centers

function findLongestPalindrome(text: string): string {
  // Preprocess: remove non-alphanumeric, lowercase
  const clean = text.toLowerCase().replace(/[^a-z0-9]/g, '');

  if (clean.length === 0) return '';

  let start = 0, end = 0;

  for (let i = 0; i < clean.length; i++) {
    // Odd length palindrome (center is character)
    const len1 = expandAroundCenter(clean, i, i);
    // Even length palindrome (center is between characters)
    const len2 = expandAroundCenter(clean, i, i + 1);

    const len = Math.max(len1, len2);

    if (len > end - start) {
      start = i - Math.floor((len - 1) / 2);
      end = i + Math.floor(len / 2);
    }
  }

  // Extract original text with preserved formatting
  return extractOriginal(text, start, end);
}

function expandAroundCenter(s: string, left: number, right: number): number {
  while (left >= 0 && right < s.length && s[left] === s[right]) {
    left--;
    right++;
  }
  return right - left - 1;
}

function extractOriginal(text: string, cleanStart: number, cleanEnd: number): string {
  // Map clean indices back to original
  const clean = text.toLowerCase().replace(/[^a-z0-9]/g, '');
  let originalStart = -1, originalEnd = -1;
  let cleanIdx = 0;

  for (let i = 0; i < text.length; i++) {
    if (/[a-z0-9]/i.test(text[i])) {
      if (cleanIdx === cleanStart) originalStart = i;
      if (cleanIdx === cleanEnd) {
        originalEnd = i;
        break;
      }
      cleanIdx++;
    }
  }

  if (originalStart === -1) return '';
  return text.substring(originalStart, originalEnd + 1);
}

